// figma-roundtrip test: Push Console Nav row (scoped)
// Source: Projects/Poalim/Components/salesforce-top-nav
// Scope: Console Nav row (row 2) with app name + 2 tabs (bare "בית", active "יצירה חדשה")
//
// Generated by applying the SKILL.md mapping table to salesforce-nav.js + salesforce-nav.css
// Target: file WpjJgZZEz03Z6GaQmIoLxV — creates a new frame on the current page

// ── Color conversion helper (from mapping table) ──
function hexToFigma(hex) {
  hex = hex.replace('#', '');
  if (hex.length === 3) hex = hex.split('').map(c => c + c).join('');
  return {
    r: parseInt(hex.substring(0, 2), 16) / 255,
    g: parseInt(hex.substring(2, 4), 16) / 255,
    b: parseInt(hex.substring(4, 6), 16) / 255,
  };
}

// ── Resolved design tokens (from :root in salesforce-nav.css) ──
const TOKENS = {
  surface:    hexToFigma('#ffffff'),
  border1:    hexToFigma('#c9c9c9'),
  text3:      hexToFigma('#001e5b'),
  accent:     hexToFigma('#0250d9'),
};

// ── Font loading (ordering rule #2: load before any text mutation) ──
await figma.loadFontAsync({ family: 'Rubik', style: 'Regular' });

// ── Position: find clear space on canvas (rule #13) ──
const pageChildren = figma.currentPage.children;
let startX = 100;
if (pageChildren.length > 0) {
  const rightmost = Math.max(...pageChildren.map(n => n.x + n.width));
  startX = rightmost + 200;
}

// ══════════════════════════════════════════════════════════════
// ROOT: .sf-console-nav
// CSS: display:flex; align-items:flex-start; justify-content:flex-start;
//      padding:4px 0; width:1306px; background:#fff; border-top:1px solid #c9c9c9
// ══════════════════════════════════════════════════════════════
const consoleNav = figma.createAutoLayout('HORIZONTAL', {
  name: 'Console Nav',
  counterAxisAlignItems: 'MIN',        // align-items: flex-start
  primaryAxisAlignItems: 'MIN',        // justify-content: flex-start
  paddingTop: 4,
  paddingBottom: 4,
  paddingLeft: 0,
  paddingRight: 0,
  itemSpacing: 0,                      // no gap — dividers are explicit children
});
consoleNav.resize(1306, 32);
consoleNav.layoutSizingHorizontal = 'FIXED';
consoleNav.fills = [{ type: 'SOLID', color: TOKENS.surface }];
// border-top: 1px solid #c9c9c9
consoleNav.strokes = [{ type: 'SOLID', color: TOKENS.border1 }];
consoleNav.strokeWeight = 1;
consoleNav.strokeAlign = 'INSIDE';
consoleNav.strokeTopWeight = 1;
consoleNav.strokeBottomWeight = 0;
consoleNav.strokeLeftWeight = 0;
consoleNav.strokeRightWeight = 0;
consoleNav.x = startX;
consoleNav.y = 100;

// ══════════════════════════════════════════════════════════════
// CHILD 1: .sf-app-name
// CSS: display:flex; gap:16px; height:32px; align-items:center;
//      justify-content:flex-end; padding-right:32px; padding-left:16px
// ══════════════════════════════════════════════════════════════
const appName = figma.createAutoLayout('HORIZONTAL', {
  name: 'App Name',
  itemSpacing: 16,                     // gap: 16px
  counterAxisAlignItems: 'CENTER',     // align-items: center
  primaryAxisAlignItems: 'MAX',        // justify-content: flex-end
  paddingRight: 32,                    // padding-right: 32px (--slds-sp-6)
  paddingLeft: 16,                     // padding-left: 16px (--slds-sp-4)
  paddingTop: 0,
  paddingBottom: 0,
});
// ordering rule #1: append before sizing
consoleNav.appendChild(appName);
appName.resize(appName.width, 32);
appName.layoutSizingVertical = 'FIXED';
appName.layoutSizingHorizontal = 'HUG';
appName.fills = [];                    // transparent

// ── App name text ──
// CSS: font-size:20px; font-weight:400; color:#001e5b; text-align:right; line-height:28px
const appNameText = figma.createText();
appNameText.name = 'App Name Text';
appName.appendChild(appNameText);
appNameText.fontName = { family: 'Rubik', style: 'Regular' };
appNameText.characters = 'קונסולת מכירות';
appNameText.fontSize = 20;
appNameText.fills = [{ type: 'SOLID', color: TOKENS.text3 }];
appNameText.textAlignHorizontal = 'RIGHT';
appNameText.lineHeight = { value: 28, unit: 'PIXELS' };
appNameText.layoutSizingHorizontal = 'HUG';
appNameText.layoutSizingVertical = 'HUG';

// ── Waffle icon placeholder ──
const waffleIcon = figma.createRectangle();
waffleIcon.name = 'icon-waffle.svg [placeholder]';
appName.appendChild(waffleIcon);
waffleIcon.resize(24, 24);
waffleIcon.layoutSizingHorizontal = 'FIXED';
waffleIcon.layoutSizingVertical = 'FIXED';
waffleIcon.fills = [{ type: 'SOLID', color: TOKENS.border1, opacity: 0.3 }];
waffleIcon.cornerRadius = 4;

// ══════════════════════════════════════════════════════════════
// Helper: createDivider
// CSS: .sf-vdivider — vertical flex, 32px; child .sf-vdivider-line — 1px, #c9c9c9
// ══════════════════════════════════════════════════════════════
function createDivider(parent) {
  const divider = figma.createAutoLayout('VERTICAL', {
    name: 'Divider',
    counterAxisAlignItems: 'MAX',      // align-items: flex-end
    primaryAxisAlignItems: 'CENTER',   // justify-content: center
  });
  parent.appendChild(divider);
  divider.resize(1, 32);
  divider.layoutSizingHorizontal = 'FIXED';
  divider.layoutSizingVertical = 'FIXED';
  divider.fills = [];

  const line = figma.createRectangle();
  line.name = 'Divider Line';
  divider.appendChild(line);
  line.resize(1, 1);
  line.layoutSizingHorizontal = 'FIXED';
  line.layoutSizingVertical = 'FILL';  // flex: 1
  line.fills = [{ type: 'SOLID', color: TOKENS.border1 }];

  return divider;
}

// ══════════════════════════════════════════════════════════════
// Helper: createTab
// CSS: .sf-nav-tab — vertical flex, 32px; .sf-nav-tab-inner — horizontal flex;
//      .sf-tab-icon-label — horizontal flex, fill;
//      .sf-nav-tab-label — 14px, #001e5b (or #0250d9 if active)
//      .sf-nav-tab-bar — 3px, white (or #0250d9 + radius 4 if active)
// ══════════════════════════════════════════════════════════════
function createTab(parent, label, active, fixedWidth) {
  // Outer: .sf-nav-tab
  const tab = figma.createAutoLayout('VERTICAL', {
    name: 'Tab: ' + label,
    counterAxisAlignItems: 'MAX',      // align-items: flex-end
    itemSpacing: 0,
  });
  parent.appendChild(tab);
  if (fixedWidth) {
    tab.resize(fixedWidth, 32);
    tab.layoutSizingHorizontal = 'FIXED';
  } else {
    tab.layoutSizingHorizontal = 'HUG';
  }
  tab.resize(tab.width, 32);
  tab.layoutSizingVertical = 'FIXED';
  tab.fills = [];

  // Inner: .sf-nav-tab-inner
  const inner = figma.createAutoLayout('HORIZONTAL', {
    name: 'Tab Inner',
    counterAxisAlignItems: 'CENTER',   // align-items: center
    primaryAxisAlignItems: 'MAX',      // justify-content: flex-end
    paddingLeft: 8,                    // padding: 0 8px
    paddingRight: 8,
    paddingTop: 0,
    paddingBottom: 0,
    itemSpacing: 0,
  });
  tab.appendChild(inner);
  inner.layoutSizingHorizontal = 'FILL';
  inner.resize(inner.width, 32);
  inner.layoutSizingVertical = 'FIXED';
  inner.fills = [{ type: 'SOLID', color: TOKENS.surface }];

  // Icon+label container: .sf-tab-icon-label
  const iconLabel = figma.createAutoLayout('HORIZONTAL', {
    name: 'Icon + Label',
    counterAxisAlignItems: 'CENTER',
    itemSpacing: 0,
  });
  inner.appendChild(iconLabel);
  iconLabel.layoutSizingHorizontal = 'FILL';  // flex: 1
  iconLabel.layoutSizingVertical = 'HUG';
  iconLabel.fills = [];

  // Tab icon placeholder
  const iconBox = figma.createAutoLayout('HORIZONTAL', {
    name: active ? 'icon-tab-active [placeholder]' : 'icon-tab-inactive [placeholder]',
    counterAxisAlignItems: 'CENTER',
    primaryAxisAlignItems: 'CENTER',
  });
  iconLabel.appendChild(iconBox);
  iconBox.resize(24, 24);
  iconBox.layoutSizingHorizontal = 'FIXED';
  iconBox.layoutSizingVertical = 'FIXED';
  iconBox.fills = [];

  const iconRect = figma.createRectangle();
  iconRect.name = 'icon';
  iconBox.appendChild(iconRect);
  iconRect.resize(16, 16);
  iconRect.layoutSizingHorizontal = 'FIXED';
  iconRect.layoutSizingVertical = 'FIXED';
  iconRect.fills = [{ type: 'SOLID', color: active ? TOKENS.accent : TOKENS.border1, opacity: 0.3 }];
  iconRect.cornerRadius = 2;

  // Tab label text
  const labelText = figma.createText();
  labelText.name = 'Tab Label';
  iconLabel.appendChild(labelText);
  labelText.fontName = { family: 'Rubik', style: 'Regular' };
  labelText.characters = label;
  labelText.fontSize = 14;
  labelText.fills = [{ type: 'SOLID', color: active ? TOKENS.accent : TOKENS.text3 }];
  labelText.textAlignHorizontal = 'RIGHT';
  labelText.lineHeight = { value: 19, unit: 'PIXELS' };
  labelText.layoutSizingHorizontal = 'FILL';
  labelText.layoutSizingVertical = 'HUG';

  // Active bar: .sf-nav-tab-bar
  const bar = figma.createRectangle();
  bar.name = active ? 'Active Bar' : 'Tab Bar';
  tab.appendChild(bar);
  bar.layoutSizingHorizontal = 'FILL';
  bar.resize(bar.width, 3);
  bar.layoutSizingVertical = 'FIXED';
  bar.fills = [{ type: 'SOLID', color: active ? TOKENS.accent : TOKENS.surface }];
  if (active) {
    bar.cornerRadius = 4;             // border-radius: 4px (--slds-radius-1)
  }

  return tab;
}

// ══════════════════════════════════════════════════════════════
// ASSEMBLE: divider + tab pairs
// ══════════════════════════════════════════════════════════════

// Divider 1
createDivider(consoleNav);

// Tab 1: bare "בית" (width: 120px)
createTab(consoleNav, 'בית', false, 120);

// Divider 2
createDivider(consoleNav);

// Tab 2: active "יצירה חדשה"
createTab(consoleNav, 'יצירה חדשה', true, null);

// ══════════════════════════════════════════════════════════════
// RETURN node IDs (skill rule: always return created IDs)
// ══════════════════════════════════════════════════════════════
return {
  rootNodeId: consoleNav.id,
  rootName: consoleNav.name,
  childCount: consoleNav.children.length,
  children: consoleNav.children.map(c => ({ id: c.id, name: c.name })),
};
